    {
        private readonly string connectionString = "Data Source=YourServer;Initial Catalog=YourDatabase;User ID=YourUsername;Password=YourPassword";

        [HttpGet]
        public IActionResult SearchUsersByEmail([FromQuery] string email)
        {
            try
            {
                using (SqlConnection connection = new SqlConnection(connectionString))
                {
                    connection.Open();

                    SqlCommand command = new SqlCommand("SELECT * FROM Users WHERE Email LIKE @email", connection);
